/*	StIntervalTimer.h		Stack-based class for measuring elapsed time. Starts measuring when constructed,	allows calls to be made for splits, and 	stops measuring and reports the splits time when destructed.		Copyright � 2004 	Tom Padula	All Rights Reserved.	Created March 12th, 2004.		*/#include "TargetConditionals.h"#import <CoreFoundation/CoreFoundation.h>#import <string>#import <map>#import <sstream>#if TARGET_OS_IPHONEtypedef std::map<const CFAbsoluteTime, std::string> 	SSplitMap;#elseclass UnsignedWideLess{public:	bool operator() (const UnsignedWide inUW1, const UnsignedWide inUW2) const		{		if (inUW1.hi < inUW2.hi)			return (true);					if (inUW1.hi > inUW2.hi)			return (false);					if (inUW1.lo < inUW2.lo)			return (true);					return (false);		}};typedef std::map<const UnsignedWide, std::string, UnsignedWideLess> 	SSplitMap;#endifclass SHumanTime	{	public:		UInt32 m_milliseconds;		UInt32 m_seconds;		UInt32 m_minutes;		UInt32 m_hours;				SHumanTime ()			{			m_milliseconds = 0;			m_seconds = 0;			m_minutes = 0;			m_hours = 0;			}					operator std::string() const			{			// Create a string of the format HH:MM:SS:mmm (12 chars)			std::stringstream aStringStream;			if (m_hours < 10)				aStringStream << "0";			aStringStream << m_hours << ":";						if (m_minutes < 10)				aStringStream << "0";			aStringStream << m_minutes << ":";						if (m_seconds < 10)				aStringStream << "0";			aStringStream << m_seconds << ":";						if (m_milliseconds < 100)				aStringStream << "0";			if (m_milliseconds < 10)				aStringStream << "0";			aStringStream << m_milliseconds;						return (aStringStream.str ());			}	};#if !TARGET_OS_IPHONEUnsignedWide UWDifference (UnsignedWide inLeft, UnsignedWide inRight);#endifclass StIntervalTimer{public: 	StIntervalTimer (std::string inTaskMessage, std::string inEndMessage = "StIntervalTimer end");	virtual ~StIntervalTimer ();		virtual void Split (std::string inSplitEventMessage);	protected:#if TARGET_OS_IPHONE	SHumanTime GetHumanTime (CFAbsoluteTime inTime);#else	SHumanTime GetHumanTime (UnsignedWide inTime);#endifprivate:	SSplitMap		m_splitMap;	std::string		m_endMessage;#if TARGET_OS_IPHONE	void ReportSplit (SSplitMap::iterator inFirst,					  SSplitMap::iterator inSecond,					  CFAbsoluteTime inTotalElapsedTime);#else	void ReportSplit (SSplitMap::iterator inFirst,					  SSplitMap::iterator inSecond,					  UnsignedWide inTotalElapsedTime);#endif};